## Create a peer
```js
const peer = new ZYNQ.Peer();
```

## Listen for ready
```js
peer.on('ready', (id) => {
  console.log('Peer ID:', id);
});
```

You use this ID to connect with other users.

## Connect to peer
```js
const conn = peer.connect('remote-id');
```

## Receive connection
```js
peer.on('connection', (conn) => {
  conn.on('open', () => {
    conn.send('Hello!');

    conn.on('data', (data) => {
      console.log('Received:', data);
    });
  });
});
```

## Start call
```js
const call = peer.call('remote-id', mediaStream);
```

## Answer call
```js
peer.on('call', (call) => {
  call.answer(mediaStream);
});
```

## Receive stream
```js
call.on('stream', (stream) => {
  video.srcObject = stream;
});
```

## Init games
```js
const games = new ZYNQ.games();
await games.init();
```

## Search games
```js
games.search('minecraft');
console.log(games.list);
```

## Reset
```js
games.reset();
```

## Favorites
```js
games.toggleFavorite('game-alias');
```

## History
```js
games.addToHistory('game-alias');
console.log(games.getHistory());
```

## Random game
```js
const game = games.getRandomOne();
```
